const request = $input.first().json;
const headers = (request.headers && typeof request.headers === 'object' && !Array.isArray(request.headers)) ? request.headers : {};
const headerValue = (value) => Array.isArray(value) ? String(value[0] || '').trim() : String(value || '').trim();
const expectedApiKey = String($env.N8N_WEBHOOK_API_KEY || '').trim();
const xApiKey = headerValue(headers['x-api-key'] ?? headers['X-API-Key']);
const authorization = headerValue(headers.authorization ?? headers.Authorization);
const bearerMatch = authorization.match(/^Bearer\s+(.+)$/i);
const bearerToken = bearerMatch ? String(bearerMatch[1] || '').trim() : '';
const authenticated = Boolean(expectedApiKey) && (xApiKey === expectedApiKey || bearerToken === expectedApiKey);

if (authenticated) {
  return [{
    json: {
      ...request,
      webhook_auth: {
        authenticated: true,
        header: xApiKey ? 'X-API-Key' : 'Authorization'
      }
    },
    pairedItem: {
      item: 0
    }
  }];
}

const message = expectedApiKey
  ? 'Unauthorized: Invalid or missing API key'
  : 'Unauthorized: N8N_WEBHOOK_API_KEY is not configured';

return [{
  json: {
    ...request,
    status: 'error',
    message,
    code: 401,
    webhook_auth: {
      authenticated: false
    }
  },
  pairedItem: {
    item: 0
  }
}];

const body = $input.first().json.body || {};

const task_type = String(body.task_type || '').trim();
const policy_scope = String(body.policy_scope || '').trim() || 'task_type_only';
let workflow_id = String(body.workflow_id || '').trim();
const tenant_id = String(body.tenant_id || '*').trim();
const scope_pattern = String(body.scope_pattern || '*').trim();
const enabled = body.enabled !== false;
const actor = String(body.actor || 'n8n-ce');
const constraints = body.constraints && typeof body.constraints === 'object' ? body.constraints : {};

if (!task_type) {
  return [{ json: { status: 'error', message: 'task_type is required' } }];
}

if (!workflow_id || policy_scope === 'task_type_only') {
  workflow_id = '*';
}

return [{
  json: { workflow_id, task_type, tenant_id, scope_pattern, enabled, actor, constraints, policy_scope }
}];
